class PIADefense:
    def __init__(self, noise_scale=0.1, mask_ratio=0.15):
        self.noise_scale = noise_scale
        self.mask_ratio = mask_ratio
    def apply(self, feat):
        noise = torch.randn_like(feat) * self.noise_scale
        B, C, H, W = feat.shape
        mask = torch.rand((B, 1, H, W), device=feat.device) > self.mask_ratio
        feat = feat * mask.float() + noise
        return feat

